import{_ as t,c as e,o,U as r}from"./chunks/framework.ZqSlfLj8.js";const m=JSON.parse('{"title":"工程化思考","description":"","frontmatter":{},"headers":[],"relativePath":"docs/frontEngineering/工程化思考.md","filePath":"docs/frontEngineering/工程化思考.md","lastUpdated":1664176337000}'),i={name:"docs/frontEngineering/工程化思考.md"},n=r('<h1 id="工程化思考" tabindex="-1">工程化思考 <a class="header-anchor" href="#工程化思考" aria-label="Permalink to &quot;工程化思考&quot;">​</a></h1><h2 id="开发规范化" tabindex="-1">开发规范化 <a class="header-anchor" href="#开发规范化" aria-label="Permalink to &quot;开发规范化&quot;">​</a></h2><ul><li><p>EditorConfig 配置文件</p></li><li><p>Prettier 配置文件</p></li><li><p>Eslint 配置文件</p></li><li><p>提交钩子</p><ul><li>Commitlint 校验commit message格式</li><li>Eslint 规则校验</li><li>Changelog 生成变更日志</li></ul></li></ul><h2 id="项目结构设计" tabindex="-1">项目结构设计 <a class="header-anchor" href="#项目结构设计" aria-label="Permalink to &quot;项目结构设计&quot;">​</a></h2><p>以<strong>组件库项目</strong>为例子设计结构 <a href="https://blog.csdn.net/caidewei121/article/details/124831298" target="_blank" rel="noreferrer">https://blog.csdn.net/caidewei121/article/details/124831298</a></p><ul><li><p><strong>组件文件夹</strong></p><p>编写组件、组件的使用文档（markdown文件）、测试用例</p></li><li><p><strong>Demo文件夹</strong></p><p>示例项目，展示编写的组件</p></li><li><p><strong>文档文件夹</strong></p><p>通常是一个Web项目，用于展示组件的使用文档</p></li></ul><p>可以看出来，所有的部分都是围绕这编写的<strong>组件文件夹</strong>展开的</p><h2 id="打包构建" tabindex="-1">打包构建 <a class="header-anchor" href="#打包构建" aria-label="Permalink to &quot;打包构建&quot;">​</a></h2><p>什么时候会涉及<strong>构建工具</strong>？</p><ul><li><p>开发过程中使用的一些内容，并不是原生支持的</p><p>比如，一个前端组件库使用的TS、Less等开发，但是浏览器环境并不支持，所以需要构建工具做转化</p></li><li><p>Dome项目不支持</p><p>如果<strong>Dome文件夹</strong>中的项目不支持，<strong>Dome文件夹</strong>中就不能直接使用<strong>组件文件夹</strong>中的组件了，这时候一般会需要构建工具做处理</p><p>比如：组件使用TS开发，但是Dome中实际的使用场景是JS。</p><p>这里需要额外注意，假设开发的是一个JS编写的插件，Demo就是一个Vue项目（也使用JS），Demo中应该展示如何使用这个组件，最好使用npm的方式，安装这个组件，然后展示。那如何把未发布的组件通npm的方式安装到项目中（lerna这个包）</p></li><li><p>项目文档</p><p>展示项目文档的Web项目，不可能完全手动维护。一般是在<strong>组件文件夹</strong>中的每个组件内写好<code>README.md</code>说明文件，通过构建工具自动生成Web项目</p></li></ul><p><strong>构建产物文件夹</strong></p><p>编写完组件后，进行构建会生成</p><p><strong>项目结构关系发生变化</strong></p><ul><li><p><strong>组件文件夹</strong></p><p>编写组件</p></li><li><p><strong>构建产物文件夹</strong></p><p>构建后生成</p></li><li><p><strong>Demo文件夹</strong></p><p>示例项目，展示编写的组件。如果组件不能直接在Dome项目中使用，则使用构建后产物</p></li><li><p><strong>测试文件夹</strong></p><p>测试编写的组件。如果不能直接测试组件，则使用构建后产物</p></li><li><p><strong>文档文件夹</strong></p><p>通常是一个Web项目，用于展示组件的使用文档</p></li></ul><h2 id="ci-cd" tabindex="-1">CI/CD <a class="header-anchor" href="#ci-cd" aria-label="Permalink to &quot;CI/CD&quot;">​</a></h2><p>提交到Git仓库后</p><ul><li><strong>自动化发布组件库</strong></li><li><strong>自动化发布Web说明文档</strong></li></ul>',17),l=[n];function a(p,s,g,d,c,h){return o(),e("div",null,l)}const u=t(i,[["render",a]]);export{m as __pageData,u as default};
